{{ now() | date(format="%+") }}
{{ config.base_url }}/

  {{ config.extra.author.name }}
  {{ config.extra.author.email }}

{% set posts = get_section(path="posts/_index.md") %}
{% for post in posts.pages %}

  {{ post.title }}

  {{ post.permalink }}
  {{ post.date | date(format="%+") }}
  {% if post.updated %}{{ post.updated | date(format="%+") }}{% else %}{{ post.date | date(format="%+") }}{% endif %}
  {% set summary_text = post.description | default(value="") %}
  {% if summary_text == "" %}{% set summary_text = post.content | striptags | truncate(length=200) %}{% endif %}
  {% if summary_text != "" %}{{ summary_text }}{% endif %}
  {% set clean = post.content | regex_replace(pattern="(?s)", rep="") | regex_replace(pattern="(?s)]*>.*?", rep="") | regex_replace(pattern="(?s)]*>.*?", rep="") %}
  {% set clean = clean | regex_replace(pattern='(src|href)="([^"]*)"', rep='$1="__ABS__$2"') %}
  {% set clean = clean | replace(from="__ABS__https://", to="https://") %}
  {% set clean = clean | replace(from="__ABS__http://", to="http://") %}
  {% set clean = clean | replace(from="__ABS__//", to="//") %}
  {% set clean = clean | replace(from="__ABS__#", to="#") %}
  {% set clean = clean | replace(from="__ABS__data:", to="data:") %}
  {% set clean = clean | replace(from="__ABS__mailto:", to="mailto:") %}
  {% set clean = clean | replace(from="__ABS__/", to=config.base_url ~ "/") %}
  {% set clean = clean | replace(from="__ABS__", to=post.permalink) %}
  {{ clean | safe }}

{% endfor %}
